		wantTotal   float64
		wantErr     bool
		errContains string // часть сообщения ошибки (если нужно проверить)
	}{
		{
			name:      "empty slice",
			order:     Order{Items: []OrderItem{}},
			wantTotal: 0,
			wantErr:   false,
		},
		{
			name:      "nil slice",
			order:     Order{Items: nil},
			wantTotal: 0,
			wantErr:   false,
		},
		{
			name: "zero quantity",
			order: Order{
				Items: []OrderItem{
